query.sparql:
SELECT ?entity ?entityLabel
WHERE {
  wd:Q761383 wdt:P138 ?entity.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}

SELECT ?animal ?operation
WHERE {
  ?animal wdt:P31 wd:Q729 .
  ?operation wdt:P710 ?militaryUnit .
  ?militaryUnit wdt:P798 ?designation .
  ?militaryUnit wdt:P7779 wd:Q625657 .
  FILTER EXISTS { ?animal wdt:P527 ?operation }
}

SELECT ?founder ?founderLabel
WHERE
{
  wd:Q8798 wdt:P112 ?founder .
  ?founder wdt:P102 wd:Q6497 .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}

SELECT ?exchange ?exchangeLabel
WHERE {
  wd:Q81230 p:P414 ?statement .
  ?statement ps:P414 ?exchange .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}

SELECT ?work ?workLabel
WHERE {
  ?author wdt:P50 ?book .
  ?book wdt:P6333 ?work .
  FILTER NOT EXISTS { ?book wdt:P6333 "The Witcher" }
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}

SELECT ?boilingPoint
WHERE {
  wd:Q283 .
  OPTIONAL {
    wd:Q283 wdt:P2102 ?boilingPoint .
    FILTER(LANGMATCHES(LANG(?boilingPoint), "en"))
  }
}

SELECT ?school ?schoolLabel
WHERE {
  wd:Q231121 wdt:P69 ?school .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}
